            XPath xPath = XPathFactory.newInstance().newXPath();

            // Create XPath expression to find the role of the user with the given username
            String expression = "//user[name=" + escapeXpath(username) + "]/role/text()";

            // Execute the XPath query
            Node resultNode = (Node) xPath.compile(expression).evaluate(document, XPathConstants.NODE);

            // Return the text content if found, otherwise return null
            if (resultNode != null) {
                return resultNode.getNodeValue();
            } else {
                return null;
            }
        } catch (ParserConfigurationException | IOException | XPathExpressionException | SAXException e) {
            throw new RuntimeException("Error parsing XML or executing XPath query", e);
        }
    }

    // Function to properly escape strings for XPath
    private String escapeXpath(String input) {
        if (input == null) {
            return "''";
        }

        // Check if the string contains single quotes
        if (input.indexOf('\'') >= 0) {
            // Use XPath's concat function to handle strings containing single quotes
            StringBuilder sb = new StringBuilder("concat(");
            boolean first = true;
            for (String part : input.split("'")) {
                if (!first) {
                    sb.append(", \"'\", ");
                }
                sb.append("'");
                sb.append(part);
                sb.append("'");
                first = false;
            }
            sb.append(")");
            return sb.toString();
        } else {
            return "'" + input + "'";
        }
    }
}
